import{_ as o,r as i,o as s,c as d,b as e,d as a,e as n,a as r}from"./app.6f1da690.js";const l={},c=r(`<h1 id="bamboo-support" tabindex="-1"><a class="header-anchor" href="#bamboo-support" aria-hidden="true">#</a> Bamboo Support</h1><p>Bamboo is a Markdown-based notes app for writing, organizing, and connecting your personal knowledge. This guide covers the main features available in the app and the most common questions about editing, organization, sync, backup, import, export, and subscriptions.</p><h2 id="getting-started" tabindex="-1"><a class="header-anchor" href="#getting-started" aria-hidden="true">#</a> Getting Started</h2><h3 id="create-a-note" tabindex="-1"><a class="header-anchor" href="#create-a-note" aria-hidden="true">#</a> Create a note</h3><p>Use the new note button in Bamboo to create a note. The first heading or first line of the note is used as the note title in lists and search results.</p><p>In <strong>Settings &gt; General</strong>, you can choose the default template Bamboo uses when creating a new note.</p><h3 id="navigate-the-app" tabindex="-1"><a class="header-anchor" href="#navigate-the-app" aria-hidden="true">#</a> Navigate the app</h3><p>Bamboo is organized around three main areas:</p><ul><li><strong>Sidebar</strong>: built-in views such as All Notes, Today, To-Dos, Starred, Pinned, Archive, Trash, collections, and smart views.</li><li><strong>Notes list</strong>: notes matching the selected sidebar item.</li><li><strong>Editor</strong>: the Markdown writing area for the selected note.</li></ul><p>On iPhone, the sidebar and inspector may appear as slide-out panels. On iPad and Mac, Bamboo uses a split-view layout when space is available.</p><h2 id="writing-and-formatting" tabindex="-1"><a class="header-anchor" href="#writing-and-formatting" aria-hidden="true">#</a> Writing and Formatting</h2><h3 id="markdown-basics" tabindex="-1"><a class="header-anchor" href="#markdown-basics" aria-hidden="true">#</a> Markdown basics</h3><p>Bamboo stores note content as Markdown. Common Markdown syntax works as expected:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token title important"><span class="token punctuation">#</span> Heading</span>

<span class="token bold"><span class="token punctuation">**</span><span class="token content">Bold text</span><span class="token punctuation">**</span></span>
<span class="token italic"><span class="token punctuation">*</span><span class="token content">Italic text</span><span class="token punctuation">*</span></span>

<span class="token list punctuation">-</span> Bullet item
<span class="token list punctuation">-</span> [ ] Todo item
<span class="token list punctuation">-</span> [x] Completed todo

<span class="token blockquote punctuation">&gt;</span> Quote

<span class="token code-snippet code keyword">\`inline code\`</span>

<span class="token code"><span class="token punctuation">\`\`\`</span><span class="token code-language">swift</span>
<span class="token code-block language-swift">print(&quot;Hello&quot;)</span>
<span class="token punctuation">\`\`\`</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The editor also supports common writing conveniences such as syntax highlighting for fenced code blocks, task lists, tables, wiki links, footnotes, underline, highlight, and math syntax.</p><h3 id="editor-shortcuts" tabindex="-1"><a class="header-anchor" href="#editor-shortcuts" aria-hidden="true">#</a> Editor shortcuts</h3><p>On macOS, Bamboo’s main editor shortcuts are exposed through the top menu bar, especially <strong>Format</strong> and <strong>Find</strong>. These are the shortcuts users should treat as the official Mac shortcut reference.</p><p>On iPhone and iPad, Bamboo also provides an editor formatting panel above the keyboard. It includes quick controls for moving lines, inserting images and files, taking photos, scanning documents, inserting tables, inserting dates, folding, headings, bold, italic, underline, strikethrough, indentation, lists, blockquotes, task lists, highlights, code, math, links, horizontal rules, superscript, subscript, and footnotes.</p><p>The macOS <strong>Format</strong> menu includes:</p><table><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Control-Command-1</code> through <code>Control-Command-6</code></td><td>Apply Heading 1 through Heading 6</td></tr><tr><td><code>Command-U</code></td><td>Underline</td></tr><tr><td><code>Control-Command-M</code></td><td>Strikethrough</td></tr><tr><td><code>Command-Shift-M</code></td><td>Highlight with the default highlight color</td></tr><tr><td><code>Command-Shift-L</code></td><td>Bullet list</td></tr><tr><td><code>Option-Command-L</code></td><td>Ordered list</td></tr><tr><td><code>Command-L</code></td><td>Task list</td></tr><tr><td><code>Command-Shift-U</code></td><td>Blockquote</td></tr><tr><td><code>Option-Command-C</code></td><td>Inline code</td></tr><tr><td><code>Control-Command-C</code></td><td>Code block</td></tr><tr><td><code>Command-Shift-T</code></td><td>Footnote</td></tr><tr><td><code>Option-Command--</code></td><td>Horizontal rule</td></tr><tr><td><code>Option-Command-T</code></td><td>Insert table</td></tr><tr><td><code>Command-K</code></td><td>Add link</td></tr><tr><td><code>Command-D</code></td><td>Insert wiki link</td></tr><tr><td><code>Control-Command-V</code></td><td>Insert attachment</td></tr><tr><td><code>Command-Shift-X</code></td><td>Inline math</td></tr></tbody></table><p>Table commands are available from the macOS <strong>Format &gt; Table</strong> menu when the cursor is inside a table:</p><table><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Control-Command-Down Arrow</code></td><td>Add row below</td></tr><tr><td><code>Control-Command-Up Arrow</code></td><td>Add row above</td></tr><tr><td><code>Control-Command-Right Arrow</code></td><td>Add column after</td></tr><tr><td><code>Control-Command-Left Arrow</code></td><td>Add column before</td></tr><tr><td><code>Control-Command-Delete</code></td><td>Delete row</td></tr><tr><td><code>Control-Shift-Command-Delete</code></td><td>Delete column</td></tr></tbody></table><p>Find commands are available on macOS when an editor is active:</p><table><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Command-F</code></td><td>Find</td></tr><tr><td><code>Option-Command-F</code></td><td>Find and replace</td></tr><tr><td><code>Command-G</code></td><td>Find next</td></tr><tr><td><code>Command-Shift-G</code></td><td>Find previous</td></tr></tbody></table><h3 id="hide-markdown-marks" tabindex="-1"><a class="header-anchor" href="#hide-markdown-marks" aria-hidden="true">#</a> Hide Markdown marks</h3><p>If you prefer a cleaner writing view, turn on <strong>Settings &gt; General &gt; Hide Markdown</strong>. Bamboo will visually reduce Markdown markup while keeping the underlying note content in Markdown.</p><h3 id="images-and-attachments" tabindex="-1"><a class="header-anchor" href="#images-and-attachments" aria-hidden="true">#</a> Images and attachments</h3><p>You can insert images and other attachments into notes. Bamboo stores imported attachments in the app database and uses internal attachment references in the Markdown.</p><p>If <strong>Settings &gt; General &gt; Save Remote Images As Local Attachments</strong> is enabled, Bamboo can save supported remote images as local attachments when note content is normalized. This helps keep images available even if the original remote URL changes later.</p><h2 id="to-dos-and-reminders" tabindex="-1"><a class="header-anchor" href="#to-dos-and-reminders" aria-hidden="true">#</a> To-Dos and Reminders</h2><h3 id="create-to-dos" tabindex="-1"><a class="header-anchor" href="#create-to-dos" aria-hidden="true">#</a> Create to-dos</h3><p>Use Markdown task list syntax:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> [ ] Buy milk
<span class="token list punctuation">-</span> [x] Send the invoice
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Bamboo extracts checkbox items from active notes and shows them in To-Do views and widgets.</p><h3 id="add-reminders" tabindex="-1"><a class="header-anchor" href="#add-reminders" aria-hidden="true">#</a> Add reminders</h3><p>Add a reminder token to a line, to-do, or heading:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code><span class="token list punctuation">-</span> [ ] Call Alex @(2026-06-01 09:00)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Supported reminder format:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>@(YYYY-MM-DD)
@(YYYY-MM-DD HH:mm)
@(YYYY-MM-DD HH:mm daily)
@(YYYY-MM-DD HH:mm weekly)
@(YYYY-MM-DD HH:mm monthly)
@(YYYY-MM-DD HH:mm yearly)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Add <code>done</code> inside the reminder token when the reminder is completed:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>Follow up @(2026-06-01 09:00 done)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>In <strong>Settings &gt; General</strong>, you can enable reminder notifications and choose the default reminder time used when a reminder has a date but no time. If notifications are denied at the system level, open the system notification settings and allow Bamboo notifications.</p><h2 id="organizing-notes" tabindex="-1"><a class="header-anchor" href="#organizing-notes" aria-hidden="true">#</a> Organizing Notes</h2><h3 id="collections" tabindex="-1"><a class="header-anchor" href="#collections" aria-hidden="true">#</a> Collections</h3><p>Collections are Bamboo’s folder-like organization system. A note can belong to one or more collections.</p><p>Collections can be nested. Bamboo represents nested collection paths with <code>/</code>, such as:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Projects/Research
Projects/Personal
Archive/2026
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>You can assign collections from the note inspector. During import, Bamboo can also place imported notes into selected collections.</p><h3 id="wiki-links" tabindex="-1"><a class="header-anchor" href="#wiki-links" aria-hidden="true">#</a> Wiki links</h3><p>Use wiki links to connect notes:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>[[Note Title]]
[[Note Title#Heading]]
[[Note Title|Display Text]]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Bamboo also recognizes embed-style Attachment:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>![[Attachment]]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Wiki links help build a connected knowledge base without needing to leave the editor.</p><h3 id="pin-star-archive-and-trash" tabindex="-1"><a class="header-anchor" href="#pin-star-archive-and-trash" aria-hidden="true">#</a> Pin, star, archive, and trash</h3><p>From a note’s context menu or inspector, you can:</p><ul><li><strong>Pin</strong> a note to keep it near the top of lists.</li><li><strong>Star</strong> a note for quick access.</li><li><strong>Archive</strong> a note to hide it from normal active-note views without deleting it.</li><li><strong>Move to Trash</strong> when you no longer need a note.</li></ul><p>Notes in Trash can be restored. From Trash, deleting a note permanently removes it.</p><h2 id="search" tabindex="-1"><a class="header-anchor" href="#search" aria-hidden="true">#</a> Search</h2><p>Use Bamboo search to find notes by keywords and phrases. Search results include note links so you can jump directly to a note.</p><p>Bamboo also includes sidebar filters for common workflows, including All Notes, Uncollected, To-Dos, Today, Starred, Pinned, Archive, Trash, collections, and smart views.</p><p>On Mac, you can configure the search panel shortcut in <strong>Settings &gt; General</strong>.</p><h2 id="import-export-backup-and-restore" tabindex="-1"><a class="header-anchor" href="#import-export-backup-and-restore" aria-hidden="true">#</a> Import, Export, Backup, and Restore</h2><h3 id="import-notes" tabindex="-1"><a class="header-anchor" href="#import-notes" aria-hidden="true">#</a> Import notes</h3><p>Bamboo can import:</p><ul><li>Markdown: <code>.md</code>, <code>.markdown</code></li><li>TextBundle: <code>.textbundle</code></li><li>TextPack: <code>.textpack</code></li></ul><p>You can select individual files or folders. Bamboo scans selected folders for supported files.</p><p>During import, you can choose whether to:</p><ul><li>Keep original file creation and modification dates.</li><li>Use the filename as the note title.</li><li>Add imported notes to selected collections.</li></ul><p>Bamboo skips duplicate notes when the imported content already exists.</p><h3 id="export-notes" tabindex="-1"><a class="header-anchor" href="#export-notes" aria-hidden="true">#</a> Export notes</h3><p>Bamboo can export selected notes as:</p><ul><li>Markdown: <code>.md</code></li><li>TextBundle: <code>.textbundle</code></li><li>TextPack: <code>.textpack</code></li><li>HTML: <code>.html</code> <em>(Pro)</em></li><li>PDF: <code>.pdf</code> <em>(Pro)</em></li></ul><p>When exporting Markdown or HTML, Bamboo writes local attachments into a folder beside the exported file and updates image references accordingly. TextBundle and TextPack include assets in the bundle format.</p><h3 id="back-up-all-notes" tabindex="-1"><a class="header-anchor" href="#back-up-all-notes" aria-hidden="true">#</a> Back up all notes</h3><p>Use <strong>Backup all notes</strong> to create a Bamboo backup file:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>.bamboobk
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Backups include active notes, note metadata, collection paths, and attachments. The backup is designed for restoring into Bamboo.</p><h3 id="restore-a-backup" tabindex="-1"><a class="header-anchor" href="#restore-a-backup" aria-hidden="true">#</a> Restore a backup</h3><p>Use <strong>Restore Backup</strong> and select a <code>.bamboobk</code> file. Bamboo restores notes and collection assignments from the backup and skips notes that already exist.</p><h2 id="icloud-sync" tabindex="-1"><a class="header-anchor" href="#icloud-sync" aria-hidden="true">#</a> iCloud Sync</h2><p>iCloud Sync is a Pro feature.</p><p>Turn it on in <strong>Settings &gt; Sync &gt; iCloud Sync</strong>. Bamboo checks whether an iCloud account is available on the current device before enabling sync.</p><p>Important notes:</p><ul><li>You must be signed in to iCloud on each device.</li><li>Sync must be enabled separately on each device.</li><li>Turning sync off on one device does not turn it off on your other devices.</li><li>If iCloud is unavailable, restricted, or temporarily unavailable, Bamboo shows the sync error in <strong>Settings &gt; Sync</strong>.</li></ul><p>The Sync settings screen also shows the last known sync time when sync metadata is available.</p><h2 id="data-retention-and-local-data" tabindex="-1"><a class="header-anchor" href="#data-retention-and-local-data" aria-hidden="true">#</a> Data Retention and Local Data</h2><p>Open <strong>Settings &gt; Data Retention</strong> to control cleanup rules.</p><p>You can choose whether Bamboo should:</p><ul><li>Keep Trash items forever or delete Trash pages after a set number of days.</li><li>Keep version history forever or delete older snapshots after a set number of days.</li><li>Run cleanup manually with <strong>Run Cleanup Now</strong>.</li></ul><p>On devices with iCloud support, <strong>Reset local data</strong> removes local Bamboo data on the current device. It does not delete your data from iCloud.</p><h2 id="appearance-and-typography" tabindex="-1"><a class="header-anchor" href="#appearance-and-typography" aria-hidden="true">#</a> Appearance and Typography</h2><p>Open <strong>Settings &gt; Appearance</strong> to adjust the editor:</p><ul><li>Text font</li><li>Heading font</li><li>Code font</li><li>Font size</li><li>Line height</li><li>Line width</li><li>Paragraph spacing</li><li>Paragraph indent</li></ul><p>Use <strong>Restore Defaults</strong> to return typography settings to Bamboo’s default values.</p><h2 id="assistant" tabindex="-1"><a class="header-anchor" href="#assistant" aria-hidden="true">#</a> Assistant</h2><p>Bamboo includes an assistant for working with your notes. Assistant features are configured in <strong>Settings &gt; Assistant</strong>.</p><h3 id="configure-a-model-provider" tabindex="-1"><a class="header-anchor" href="#configure-a-model-provider" aria-hidden="true">#</a> Configure a model provider</h3><p>Before using model-backed assistant features, add a provider and at least one chat model.</p><p>When adding a provider, Bamboo asks for:</p><ul><li>Display name</li><li>Provider type</li><li>Base URL, when required by that provider</li><li>API key</li></ul><p>Provider API keys are stored securely by the app. The provider record is stored in Bamboo’s database, while the secret key is kept separately in secure storage.</p><h3 id="add-and-choose-models" tabindex="-1"><a class="header-anchor" href="#add-and-choose-models" aria-hidden="true">#</a> Add and choose models</h3><p>After adding a provider, add a model with:</p><ul><li>Display name</li><li>Model identifier</li><li>Provider</li><li>Temperature</li><li>Top P</li></ul><p>Use <strong>Default Chat Model</strong> to choose the model Bamboo uses for new assistant conversations. Use <strong>Title Generation Model</strong> if you want Bamboo to generate a conversation title after the first assistant step.</p><h3 id="tool-permissions" tabindex="-1"><a class="header-anchor" href="#tool-permissions" aria-hidden="true">#</a> Tool permissions</h3><p>Bamboo’s assistant can use tools to read and work with your notes, such as searching notes, listing collections, reading note content, updating note content, editing to-dos, and updating collections.</p><p>In <strong>Default Permissions</strong>, choose whether new chats should ask before running tools or start with broader access. Bamboo also tracks remembered permissions for higher-risk operations, such as delete operations or external side effects. You can remove individual remembered permissions or clear them all in <strong>Dangerous Operation Permissions</strong>.</p><h3 id="history-compaction" tabindex="-1"><a class="header-anchor" href="#history-compaction" aria-hidden="true">#</a> History compaction</h3><p>Assistant conversations can grow long. In <strong>History Compaction</strong>, Bamboo lets you set a token window. When recent assistant usage exceeds that window, Bamboo summarizes older history so the conversation can continue with less context pressure.</p><p>Some assistant capabilities require Pro access and a configured model provider.</p><h2 id="widgets" tabindex="-1"><a class="header-anchor" href="#widgets" aria-hidden="true">#</a> Widgets</h2><p>Bamboo includes Home Screen and desktop widgets backed by the app’s shared database.</p><p>Currently available widgets include:</p><ul><li><strong>Single Note</strong>: choose one note and keep it visible.</li><li><strong>To-Dos</strong>: show extracted checkbox items from active notes.</li><li><strong>Notes</strong>: show recent notes from All Notes, Uncollected, To-Do, Today, a Smart View, or a collection.</li><li><strong>Last Edited Note</strong>: reopen the most recently edited note.</li></ul><p>On iOS 18 and later, Bamboo also provides Control Center controls for:</p><ul><li>Create Note</li><li>Search Notes</li></ul><p>Tapping a widget opens Bamboo through an app link. To-do widgets can toggle a to-do directly from the widget when interactive widgets are supported by the system. If the widget says the database is unavailable or shows no content, open Bamboo once and make sure the app and widget can access the shared app group data.</p><h2 id="browser-clipping" tabindex="-1"><a class="header-anchor" href="#browser-clipping" aria-hidden="true">#</a> Browser Clipping</h2><p>Bamboo supports clipped Markdown imports through its app link system and Safari extension integration.</p><p>A clip can include:</p><ul><li>Title</li><li>Markdown content</li><li>Optional collection path, such as <code>Research/Web</code></li><li>Clipboard mode, where Bamboo reads the clip content from the system clipboard</li></ul><p>When a clip includes a collection path, Bamboo creates missing collection path segments as needed and places the new note there. The clipped content is imported as Markdown and then handled like any other Bamboo note.</p><h2 id="advanced-app-links-cli-and-mcp" tabindex="-1"><a class="header-anchor" href="#advanced-app-links-cli-and-mcp" aria-hidden="true">#</a> Advanced: App Links, CLI, and MCP</h2><p>Bamboo supports app links using the <code>bamboo://</code> URL scheme. These are useful for shortcuts, widgets, automations, and integrations with other apps.</p><p>Supported actions include:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bamboo://main
bamboo://create-note
bamboo://search?query=...
bamboo://open-note?id=&lt;note-uuid&gt;
bamboo://open-note?title=&lt;note-title&gt;
bamboo://note/&lt;note-uuid&gt;
bamboo://collection?id=&lt;collection-uuid&gt;
bamboo://smart-view?id=&lt;smart-view-uuid&gt;
bamboo://clip?title=...&amp;content=...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Note links can also include a text range or heading target:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bamboo://open-note?id=&lt;note-uuid&gt;&amp;from=&lt;offset&gt;&amp;to=&lt;offset&gt;
bamboo://open-note?id=&lt;note-uuid&gt;&amp;header=&lt;heading&gt;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Clip links support either direct content or clipboard import:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bamboo://clip?title=Example&amp;content=&lt;markdown&gt;
bamboo://clip?title=Example&amp;collection=Research/Web&amp;clipboard=1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="command-line" tabindex="-1"><a class="header-anchor" href="#command-line" aria-hidden="true">#</a> Command line</h3><p>Bamboo includes <code>bamboocli</code> for command-line workflows.</p><p>Common commands include:</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code>bamboocli search <span class="token string">&quot;query&quot;</span>
bamboocli list --filter pinned
bamboocli show &lt;note-uuid&gt;
bamboocli create --content <span class="token string">&quot;# New note&quot;</span>
bamboocli overwrite &lt;note-uuid&gt; --content <span class="token string">&quot;# Replacement&quot;</span>
bamboocli replace &lt;note-uuid&gt; --text <span class="token string">&quot;Updated line&quot;</span> --line <span class="token number">3</span>
bamboocli collections
bamboocli todos
bamboocli edit-todo &lt;todo-uuid&gt; --text <span class="token string">&quot;[x] Done&quot;</span>
bamboocli mcp-server
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>list</code> command supports filters such as <code>allNotes</code>, <code>uncollected</code>, <code>toDo</code>, <code>today</code>, <code>starred</code>, <code>pinned</code>, <code>archive</code>, and <code>trash</code>. Output can be rendered as TSV, CSV, or JSON with <code>--format</code>.</p><h3 id="mcp-server" tabindex="-1"><a class="header-anchor" href="#mcp-server" aria-hidden="true">#</a> MCP server</h3><p><code>bamboocli mcp-server</code> runs Bamboo’s MCP server over stdio. It exposes note tools for creating notes, reading note content, replacing ranges, searching notes, listing notes, listing collections, listing to-dos, and editing to-dos.</p><p>Most MCP clients use the same JSON config shape:</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;mcpServers&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;bamboo&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
      <span class="token property">&quot;command&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/Applications/Bamboo.app/Contents/MacOS/bamboocli&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;args&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;mcp-server&quot;</span><span class="token punctuation">]</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>These advanced features are intended for automation and developer workflows.</p><h2 id="subscription-and-pro-features" tabindex="-1"><a class="header-anchor" href="#subscription-and-pro-features" aria-hidden="true">#</a> Subscription and Pro Features</h2><p>Bamboo Pro is available as a monthly or yearly subscription through the App Store.</p><p>Pro-gated areas currently include:</p><ul><li>iCloud Sync</li><li>Assistant configuration and advanced assistant workflows</li><li>HTML export</li><li>PDF export</li></ul><p>Bamboo checks App Store entitlements to determine whether Pro is active. Subscription management, cancellation, renewal, and purchase restoration are handled through Apple’s App Store system. If subscription products or entitlements cannot be loaded, try again later and confirm that the device can reach the App Store.</p><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a> Troubleshooting</h2><h3 id="icloud-sync-will-not-turn-on" tabindex="-1"><a class="header-anchor" href="#icloud-sync-will-not-turn-on" aria-hidden="true">#</a> iCloud Sync will not turn on</h3><p>Check that:</p><ul><li>Bamboo Pro is active.</li><li>You are signed in to iCloud on this device.</li><li>iCloud is not restricted by Screen Time, device management, or account settings.</li><li>The device has network access.</li></ul><p>If iCloud is restricted, temporarily unavailable, or Bamboo cannot determine account status, the Sync settings screen shows an error message.</p><h3 id="notes-are-not-appearing-on-another-device" tabindex="-1"><a class="header-anchor" href="#notes-are-not-appearing-on-another-device" aria-hidden="true">#</a> Notes are not appearing on another device</h3><p>Confirm that:</p><ul><li>Bamboo Pro is active.</li><li>iCloud Sync is enabled on both devices.</li><li>Both devices are signed in to the intended iCloud account.</li><li>The device has network access.</li></ul><p>Turning sync off on one device does not turn it off everywhere. Check the Sync setting on each device separately.</p><h3 id="last-sync-says-never" tabindex="-1"><a class="header-anchor" href="#last-sync-says-never" aria-hidden="true">#</a> Last sync says Never</h3><p>This can happen before Bamboo has sync metadata from iCloud. Leave Bamboo open with network access and check <strong>Settings &gt; Sync</strong> again after changes have had time to upload and download.</p><h3 id="import-says-files-were-skipped" tabindex="-1"><a class="header-anchor" href="#import-says-files-were-skipped" aria-hidden="true">#</a> Import says files were skipped</h3><p>Bamboo skips duplicate notes when the same content already exists. If all selected files are duplicates, the import may report that there are no new notes to import.</p><h3 id="imported-markdown-images-are-missing" tabindex="-1"><a class="header-anchor" href="#imported-markdown-images-are-missing" aria-hidden="true">#</a> Imported Markdown images are missing</h3><p>When importing Markdown files with local images, keep the image files in the same folder structure referenced by the Markdown. On macOS, Bamboo may ask for folder access so it can read those assets.</p><h3 id="exported-markdown-has-an-extra-folder" tabindex="-1"><a class="header-anchor" href="#exported-markdown-has-an-extra-folder" aria-hidden="true">#</a> Exported Markdown has an extra folder</h3><p>That folder contains exported attachments. Keep it beside the <code>.md</code> file so image links continue to work.</p><h3 id="pdf-or-html-export-is-disabled" tabindex="-1"><a class="header-anchor" href="#pdf-or-html-export-is-disabled" aria-hidden="true">#</a> PDF or HTML export is disabled</h3><p>HTML and PDF export require Bamboo Pro. Markdown, TextBundle, and TextPack export are available without Pro.</p><h3 id="reminder-notifications-do-not-appear" tabindex="-1"><a class="header-anchor" href="#reminder-notifications-do-not-appear" aria-hidden="true">#</a> Reminder notifications do not appear</h3><p>Make sure <strong>Settings &gt; General &gt; Enable Reminder Notification</strong> is turned on and that Bamboo is allowed to send notifications in the system settings.</p><p>Also check the reminder syntax. A reminder should look like:</p><div class="language-markdown line-numbers-mode" data-ext="md"><pre class="language-markdown"><code>@(2026-06-01 09:00)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>The date must use <code>YYYY-MM-DD</code>, and the time must use 24-hour <code>HH:mm</code> format.</p><h3 id="widgets-show-no-notes" tabindex="-1"><a class="header-anchor" href="#widgets-show-no-notes" aria-hidden="true">#</a> Widgets show no notes</h3><p>Open Bamboo once so the shared database is initialized and available to widgets. For configurable widgets such as Single Note or Notes, edit the widget and choose the note or location you want to display.</p><h3 id="assistant-cannot-respond" tabindex="-1"><a class="header-anchor" href="#assistant-cannot-respond" aria-hidden="true">#</a> Assistant cannot respond</h3><p>Check <strong>Settings &gt; Assistant</strong>:</p><ul><li>A provider has been added.</li><li>The provider has a valid API key.</li><li>A chat model has been added for that provider.</li><li>A default chat model is selected.</li></ul><p>If the provider uses a custom endpoint, confirm that the Base URL and model identifier match your provider’s requirements.</p><h2 id="contact-and-policies" tabindex="-1"><a class="header-anchor" href="#contact-and-policies" aria-hidden="true">#</a> Contact and Policies</h2><p>You can open Bamboo’s support and privacy pages from <strong>Settings</strong>:</p>`,179),p={href:"https://zhigui.github.io/app-docs/bamboo/support.html",target:"_blank",rel:"noopener noreferrer"},h={href:"https://zhigui.github.io/app-docs/bamboo/privacy_policy.html",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,"For subscription terms, Bamboo uses Apple’s standard End User License Agreement:",-1),m={href:"https://www.apple.com/legal/internet-services/itunes/dev/stdeula/",target:"_blank",rel:"noopener noreferrer"};function b(g,v){const t=i("ExternalLinkIcon");return s(),d("div",null,[c,e("ul",null,[e("li",null,[a("Support: "),e("a",p,[a("https://zhigui.github.io/app-docs/bamboo/support.html"),n(t)])]),e("li",null,[a("Privacy Policy: "),e("a",h,[a("https://zhigui.github.io/app-docs/bamboo/privacy_policy.html"),n(t)])])]),u,e("p",null,[e("a",m,[a("https://www.apple.com/legal/internet-services/itunes/dev/stdeula/"),n(t)])])])}const k=o(l,[["render",b],["__file","support.html.vue"]]);export{k as default};
